/**
 * нҒҙлқјмқҙм–ёнҠё мёЎм—җм„ң нҢҢмқј лӢӨмҡҙлЎңл“ңлҘј мӢӨн–үн•©лӢҲлӢӨ.
 *
 *@paramdata - лӢӨмҡҙлЎңл“ңн•  лҚ°мқҙн„° (string, ArrayBuffer, Blob л“ұ)
 *@paramfileName - м ҖмһҘлҗ  нҢҢмқјлӘ…
 *@parammimeType - MIME нғҖмһ… (кё°ліёк°’: 'text/plain;charset=utf-8')
 */
function downloadFile(
  data: string | ArrayBuffer | Blob,
  fileName: string,
  mimeType: string = 'text/plain;charset=utf-8'
): void {
  // 1. Blob к°қмІҙ мғқм„ұ
  const blob = data instanceof Blob
    ? data
    : new Blob([data], { type: mimeType });

  // 2. Object URL мғқм„ұ
  const url = URL.createObjectURL(blob);

  // 3. мһ„мӢң <a> нғңк·ё мғқм„ұ л°Ҹ нҒҙлҰӯ
  const link = document.createElement('a');
  link.href = url;
  link.download = fileName;

  // м ‘к·јм„ұ: мҠӨнҒ¬лҰ° лҰ¬лҚ”лҘј мң„н•ң м„ӨлӘ…
  link.setAttribute('aria-label', `${fileName} лӢӨмҡҙлЎңл“ң`);

  // DOMм—җ м¶”к°Җн•ҳм§Җ м•Ҡкі  нҒҙлҰӯ (лҢҖл¶Җл¶„мқҳ нҳ„лҢҖ лёҢлқјмҡ°м Җм—җм„ң лҸҷмһ‘)
  link.click();

  // 4. л©”лӘЁлҰ¬ м •лҰ¬
  URL.revokeObjectURL(url);

  // м„ нғқмӮ¬н•ӯ: link мҡ”мҶҢ м ңкұ° (н•„мҡ”мӢң)
  // link.remove();
}

function downloadCSV(): void {
  const csvData = [
    ['мқҙлҰ„', 'лӮҳмқҙ', 'м§Ғм—…'],
    ['нҷҚкёёлҸҷ', '30', 'к°ңл°ңмһҗ'],
    ['к№ҖмІ мҲҳ', '25', 'л””мһҗмқҙл„Ҳ']
  ];

  // CSV нҳ•мӢқмңјлЎң ліҖнҷҳ
  const csvContent = csvData
    .map(row => row.join(','))
    .join('\n');

  downloadFile(
    csvContent,
    'data.csv',
    'text/csv;charset=utf-8;'
  );
}

function downloadCanvasImage(canvasId: string): void {
  const canvas = document.getElementById(canvasId) as HTMLCanvasElement;

  if (!canvas) {
    console.error('CanvasлҘј м°ҫмқ„ мҲҳ м—ҶмҠөлӢҲлӢӨ.');
    return;
  }

  // CanvasлҘј BlobмңјлЎң ліҖнҷҳ (л№„лҸҷкё°)
  canvas.toBlob((blob) => {
    if (!blob) {
      console.error('Blob мғқм„ұ мӢӨнҢЁ');
      return;
    }

    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = 'canvas-image.png';
    link.click();
    URL.revokeObjectURL(url);
  }, 'image/png');
}

function downloadBase64Image(base64Data: string, fileName: string): void {
  // data:image/png;base64, н—ӨлҚ” м ңкұ°
  const base64Content = base64Data.includes('base64,')
    ? base64Data.split('base64,')[1]
    : base64Data;

  // Base64лҘј л°”мқҙл„ҲлҰ¬лЎң ліҖнҷҳ
  const binaryString = atob(base64Content);
  const bytes = new Uint8Array(binaryString.length);

  for (let i = 0; i < binaryString.length; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  const blob = new Blob([bytes], { type: 'image/png' });
  const url = URL.createObjectURL(blob);

  const link = document.createElement('a');
  link.href = url;
  link.download = fileName;
  link.click();

  URL.revokeObjectURL(url);
}

